<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Ubuntu Desktop</title>
<style>
    /* Reset & Base */
    * { box-sizing: border-box; }
    body, html { margin: 0; padding: 0; width: 100%; height: 100%; overflow: hidden; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; background-color: #2c001e; }

    /* Desktop */
    #desktop { position: relative; width: 100%; height: 100%; display: flex; flex-direction: column; justify-content: space-between; z-index: 1; }

    /* Wallpaper (CSS Pattern) */
    #wallpaper { position: absolute; top: 0; left: 0; width: 100%; height: 100%; background: linear-gradient(135deg, #2c001e 0%, #4a0036 100%); z-index: -1; }

    /* Taskbar */
    #taskbar { display: flex; gap: 10px; padding: 10px; background: rgba(0, 0, 0, 0.8); align-items: center; border-top: 1px solid #555; z-index: 100; }
    #taskbar button { padding: 8px 16px; cursor: pointer; background: #333; color: white; border: none; border-radius: 4px; font-size: 14px; transition: background 0.2s; }
    #taskbar button:hover { background: #555; }

    /* Windows */
    .window { position: absolute; top: 50px; left: 50px; width: 600px; height: 400px; min-width: 360px; min-height: 240px; background: #383838; border-radius: 6px; box-shadow: 0 10px 30px rgba(0,0,0,0.5); display: flex; flex-direction: column; overflow: hidden; z-index: 10; }
    .window.hidden { display: none !important; }

    /* Title Bar */
    .title-bar { background: #2c2c2c; padding: 8px 12px; display: flex; justify-content: space-between; align-items: center; cursor: default; user-select: none; border-bottom: 1px solid #444; }
    .title-bar span { font-weight: bold; color: #ddd; pointer-events: none; }
    .win-close { background: transparent; border: none; color: #aaa; font-size: 18px; cursor: pointer; padding: 0; line-height: 1; }
    .win-close:hover { color: #fff; }

    /* Content */
    .content { flex: 1; overflow: auto; padding: 10px; display: flex; flex-direction: column; background: #2c2c2c; }

    /* Files App Specifics */
    #files-path { font-size: 14px; margin-bottom: 10px; color: #ddd; word-break: break-all; }
    #files-up { align-self: flex-start; padding: 5px 10px; margin-bottom: 10px; cursor: pointer; background: #555; border: none; color: white; border-radius: 3px; }
    .fs-item { display: inline-block; width: 80px; text-align: center; padding: 10px; margin: 5px; border: 1px solid transparent; cursor: pointer; color: #ddd; user-select: none; }
    .fs-item:hover { background: rgba(255,255,255,0.1); border-color: #7696b5; border-radius: 4px; }

    /* Notepad Specifics */
    #tabs { display: flex; align-items: center; gap: 5px; margin-bottom: 5px; overflow-x: auto; padding-bottom: 2px; }
    #new-tab { background: #555; border: none; color: white; padding: 4px 8px; cursor: pointer; font-size: 12px; border-radius: 3px; }
    .tab { background: #444; padding: 6px 12px; margin-right: 2px; cursor: pointer; border-radius: 4px 4px 0 0; color: #aaa; font-size: 13px; display: flex; align-items: center; gap: 8px; min-width: 80px; justify-content: space-between; }
    .tab.active { background: #2c2c2c; color: white; border-top: 2px solid #7696b5; }
    #editor { flex: 1; width: 100%; background: #2c2c2c; color: #eee; border: none; resize: none; padding: 10px; font-family: monospace; outline: none; }

</style>
</head>
<body>

<div id="desktop">
    <div id="wallpaper"></div>

    <!-- Files Window -->
    <div id="files-window" class="window hidden">
        <div class="title-bar" onmousedown="startDrag(event, 'files-window')">
            <span>Files</span>
            <button class="win-close" onclick="closeWindow('files-window')">×</button>
        </div>
        <div class="content">
            <div id="files-path">/</div>
            <button id="files-up" onclick="navigateUp()">↑ Up</button>
            <div id="fs-list"></div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window hidden">
        <div class="title-bar" onmousedown="startDrag(event, 'notepad-window')">
            <span>Notepad</span>
            <button class="win-close" onclick="closeWindow('notepad-window')">×</button>
        </div>
        <div class="content">
            <div id="tabs"></div>
            <button id="new-tab" onclick="createNewTab()">+ New Tab</button>
            <textarea id="editor" oninput="saveCurrentTab()"></textarea>
        </div>
    </div>

    <!-- Taskbar -->
    <div id="taskbar">
        <button id="open-files" onclick="openWindow('files-window')">Files</button>
        <button id="open-notepad" onclick="openWindow('notepad-window')">Notepad</button>
    </div>
</div>

<script>
// --- File System Data ---
const fileSystem = {
    '/': ['bin', 'etc', 'home', 'usr', 'var'],
    '/home': ['user'],
    '/home/user': ['Documents', 'Downloads', 'Pictures']
};

// --- State ---
let currentPath = ['/']; // Array of path segments, starts at root '/'
let activeTabId = null;
let tabs = []; // { id: string, content: string }

// --- Initialization ---
window.onload = () => {
    loadNotepadState();
    renderFiles();
};

// --- Window Management ---
function openWindow(id) {
    const win = document.getElementById(id);
    win.classList.remove('hidden');
    bringToFront(win);
}

function closeWindow(id) {
    document.getElementById(id).classList.add('hidden');
}

function bringToFront(element) {
    const windows = document.querySelectorAll('.window');
    let maxZ = 0;
    windows.forEach(w => {
        const z = parseInt(window.getComputedStyle(w).zIndex);
        if (z > maxZ) maxZ = z;
    });
    element.style.zIndex = maxZ + 1;
}

// --- File System Logic ---
function renderFiles() {
    const pathEl = document.getElementById('files-path');
    const listEl = document.getElementById('fs-list');

    // Build current path string for display
    let pathStr = '';
    if (currentPath.length === 1 && currentPath[0] === '/') {
        pathStr = '/';
    } else {
        pathStr = '/' + currentPath.join('/');
    }
    pathEl.textContent = pathStr;

    // Determine current directory contents
    const dirKey = pathStr;
    let items = fileSystem[dirKey];

    if (!items) {
        listEl.innerHTML = '<div style="color:#888">Empty Directory</div>';
        return;
    }

    listEl.innerHTML = '';
    items.forEach(name => {
        const item = document.createElement('div');
        item.className = 'fs-item';
        item.textContent = name;

        // Check if it's a folder (exists in fileSystem)
        if (fileSystem[dirKey + '/' + name] !== undefined || name === '/') {
            item.ondblclick = () => {
                const newPath = [...currentPath, name];
                currentPath = newPath;
                renderFiles();
            };
        } else {
            // File - just visual for now
            item.style.cursor = 'default';
            item.title = "File (read-only)";
        }

        listEl.appendChild(item);
    });
}

function navigateUp() {
    if (currentPath.length > 1) {
        currentPath.pop();
        renderFiles();
    } else {
        // Already at root, do nothing
    }
}

// --- Notepad Logic ---
function loadNotepadState() {
    const saved = localStorage.getItem('ubuntu_notepad_tabs');
    if (saved) {
        try {
            tabs = JSON.parse(saved);
            activeTabId = tabs[0].id; // Default to first tab
            renderTabs();
            updateEditor();
        } catch (e) {
            initDefaultTab();
        }
    } else {
        initDefaultTab();
    }
}

function initDefaultTab() {
    tabs = [{ id: Date.now().toString(), content: '' }];
    activeTabId = tabs[0].id;
    saveNotepadState();
    renderTabs();
    updateEditor();
}

function createNewTab() {
    const newId = Date.now().toString();
    tabs.push({ id: newId, content: '' });
    activeTabId = newId;
    saveNotepadState();
    renderTabs();
    updateEditor();
}

function switchTab(id) {
    activeTabId = id;
    renderTabs();
    updateEditor();
}

function saveCurrentTab() {
    const textarea = document.getElementById('editor');
    const tab = tabs.find(t => t.id === activeTabId);
    if (tab) {
        tab.content = textarea.value;
        saveNotepadState();
    }
}

function saveNotepadState() {
    localStorage.setItem('ubuntu_notepad_tabs', JSON.stringify(tabs));
}

function renderTabs() {
    const container = document.getElementById('tabs');
    container.innerHTML = '';

    tabs.forEach((tab, index) => {
        const tabEl = document.createElement('div');
        tabEl.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
        tabEl.textContent = `Tab ${index + 1}`;

        tabEl.onclick = () => switchTab(tab.id);
        container.appendChild(tabEl);
    });
}

function updateEditor() {
    const textarea = document.getElementById('editor');
    const tab = tabs.find(t => t.id === activeTabId);
    if (tab) {
        textarea.value = tab.content;
    } else {
        textarea.value = '';
    }
}

// --- Dragging Logic ---
let isDragging = false;
let dragOffsetX, dragOffsetY;
let currentWindow = null;

function startDrag(e, windowId) {
    if (e.target.closest('.win-close')) return;

    const win = document.getElementById(windowId);
    isDragging = true;
    currentWindow = win;
    bringToFront(win);

    const rect = win.getBoundingClientRect();
    dragOffsetX = e.clientX - rect.left;
    dragOffsetY = e.clientY - rect.top;
}

document.addEventListener('mousemove', (e) => {
    if (isDragging && currentWindow) {
        let x = e.clientX - dragOffsetX;
        let y = e.clientY - dragOffsetY;

        const winW = currentWindow.offsetWidth;
        const winH = currentWindow.offsetHeight;

        if (y < 0) y = 0;
        if (x < 0) x = 0;

        currentWindow.style.left = `${x}px`;
        currentWindow.style.top = `${y}px`;
    }
});

document.addEventListener('mouseup', () => {
    isDragging = false;
    currentWindow = null;
});

</script>
</body>
</html>
